import React from 'react';
import InfiniteScroll from 'react-infinite-scroll-component';
import { Card } from 'react-bootstrap';
import CommunityGalleryImage from './CommunityGalleryImage';

const CommunityGallery = ({ images, loading }) => {
  return (
    <>
      <InfiniteScroll
        dataLength={images.length}
        next={() => {}}
        hasMore={() => {}}
        loader={
          <p />
        }
      >
        <Card className="image-grid-cg">
          {!loading
            ? images.map(galleryImage => (
                <CommunityGalleryImage image={galleryImage} />
              ))
            : ''}
        </Card>
      </InfiniteScroll>
    </>
  );
};

export default CommunityGallery;
