import React, { useState } from 'react';
import GalleryModal from './GalleryModal';
import mainbit from "../images/main.png";

const CommunityGalleryImage = props => {
  const [modalShow, setModalShow] = useState(false);
  const { image } = props;

  return (
    <div
      className="image-item community"
      key={'image-' + image.number}
    >
      <img
        className="img-fluid"
        src={image.image}
        alt={'image' + image.number}
        onClick={() => setModalShow(true)}
      />
      <p>
        #{image.title}
      </p>
      <GalleryModal
        image={image}
        show={modalShow}
        onHide={() => setModalShow(false)}
      />
    </div>
  );
};

export default CommunityGalleryImage;
